    14→const messagesEmpty = document.getElementById('messages-empty');
    15→const notSupported  = document.getElementById('not-supported');
    16→const settingsBtn   = document.getElementById('settings-btn');
    17→const modalOverlay  = document.getElementById('modal-overlay');
    18→const modalClose    = document.getElementById('modal-close');
