    33→let wakeMode              = false;
    34→let wakeTriggered         = false; // transitioning from wake → main recording
    35→let wakeTriggeredRecording = false; // current recording was initiated by wake word
    36→let wakeRestartTimer      = null;
    37→const WAKE_PHRASES        = ['hey chill', 'hey chil']; // core phrase + common partial
