   110→/* ===== Speech Recognition setup ===== */
   111→const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
   112→
   113→if (!SpeechRecognition) {
   114→  notSupported.hidden = false;
   115→  micBtn.disabled = true;
   116→  micBtn.setAttribute('aria-disabled', 'true');
   117→} else {
   118→  initRecognition();
   119→}
