  background: var(--surface-hover);
  color: var(--text);
  outline: none;
}

/* ===== Messages ===== */
.messages {
  flex: 1;
  overflow-y: auto;
  padding: 12px 20px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: thin;
  scrollbar-color: var(--border) transparent;
}

.messages::-webkit-scrollbar {
  width: 4px;
}

.messages::-webkit-scrollbar-track {
  background: transparent;
}

.messages::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 2px;
}

.messages-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
}

.messages-empty p {
  color: var(--text-muted);
  font-size: 0.9rem;
  text-align: center;
}

/* Message bubble */
.message {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  border-bottom-right-radius: 4px;
  padding: 12px 16px;
  max-width: 100%;
  word-break: break-word;
  animation: slide-up 0.25s ease both;
}

.message.sending {
  opacity: 0.6;
}

.message.sent {
  border-color: rgba(233, 69, 96, 0.2);
}

.message.error {
  border-color: rgba(255, 80, 80, 0.3);
}

.message-text {
  font-size: 0.95rem;
  line-height: 1.5;
  color: var(--text);
}

.message-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 6px;
}

.message-time {
  font-size: 0.75rem;
  color: var(--text-muted);
}

.message-status {
  font-size: 0.72rem;
  padding: 2px 7px;
  border-radius: 20px;
  background: var(--surface);
  color: var(--text-muted);
}

.message.sent .message-status {
  background: rgba(233, 69, 96, 0.15);
  color: var(--accent);
}

.message.error .message-status {
  background: rgba(255, 80, 80, 0.15);
  color: #ff6b6b;
}

@keyframes slide-up {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ===== Live Transcript ===== */
.live-transcript {
  margin: 0 20px 8px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
  animation: fade-in 0.2s ease;
}

.live-transcript p {
  font-size: 0.92rem;
  color: var(--text-muted);
  font-style: italic;
  line-height: 1.5;
  min-height: 1.4em;
}

.live-transcript p.has-text {
  color: var(--text);
  font-style: normal;
}

/* ===== Transcript Bar (post-recording) ===== */
.transcript-bar {
  margin: 0 20px 12px;
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  animation: slide-up 0.2s ease;
}

.transcript-text {
  font-size: 0.95rem;
  line-height: 1.5;
  color: var(--text);
  margin-bottom: 14px;
  word-break: break-word;
}

.transcript-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
}

/* ===== Buttons ===== */
.btn-ghost {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-muted);
  border-radius: var(--radius-sm);
  padding: 8px 18px;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all var(--transition);
}

.btn-ghost:hover, .btn-ghost:focus-visible {
  background: var(--surface);
  color: var(--text);
  outline: none;
}

.btn-send {
  background: var(--accent);
  border: none;
  color: #fff;
  border-radius: var(--radius-sm);
  padding: 8px 22px;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: all var(--transition);
  box-shadow: 0 2px 12px rgba(233, 69, 96, 0.35);
}

.btn-send:hover, .btn-send:focus-visible {
  background: #ff5c75;
  outline: none;
  box-shadow: 0 4px 20px rgba(233, 69, 96, 0.55);
}

/* ===== Mic Section ===== */
.mic-section {
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 16px 20px 36px;
  gap: 16px;
}

.mic-hint {
  font-size: 0.85rem;
  color: var(--text-muted);
  letter-spacing: 0.04em;
  transition: color var(--transition);
  min-height: 1.2em;
}

.mic-hint.active {
  color: var(--accent);
}

/* Dual-mode button container */
.mic-buttons {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  gap: 28px;
}

.mode-btn-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
}

.mode-label {
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text-muted);
  transition: color var(--transition);
}

.mode-label.brainstorm-label {
  color: rgba(163, 121, 221, 0.7);
}

/* Shrink buttons slightly for side-by-side layout */
.mic-buttons .mic-ring {
  width: 112px;
  height: 112px;
}

.mic-buttons .mic-btn {
  width: 76px;
  height: 76px;
}

.mic-buttons .mic-icon {
  width: 30px;
  height: 30px;
}

/* Ring / glow around button */
.mic-ring {
  position: relative;
  width: var(--ring-size);
  height: var(--ring-size);
  display: flex;
  align-items: center;
  justify-content: center;
}

.mic-ring::before,
.mic-ring::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 2px solid transparent;
  transition: all 0.3s ease;
}

.mic-ring.recording::before {
  border-color: var(--accent-glow);
  animation: ring-pulse 1.4s ease-in-out infinite;
}

.mic-ring.recording::after {
  border-color: rgba(233, 69, 96, 0.15);
  animation: ring-pulse 1.4s ease-in-out 0.7s infinite;
}

@keyframes ring-pulse {
  0%   { transform: scale(1); opacity: 1; }
  100% { transform: scale(1.6); opacity: 0; }
}

/* The mic button */
.mic-btn {
  position: relative;
  width: var(--mic-size);
  height: var(--mic-size);
  border-radius: 50%;
  border: none;
  background: linear-gradient(145deg, var(--bg-3), var(--accent-2));
  color: #fff;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.4),
    0 0 0 1px rgba(255, 255, 255, 0.08);
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  -webkit-user-select: none;
  user-select: none;
  touch-action: manipulation;
  z-index: 1;
}

.mic-btn:hover {
  transform: scale(1.05);
  box-shadow:
    0 6px 32px rgba(0, 0, 0, 0.5),
    0 0 0 1px rgba(255, 255, 255, 0.12);
}

.mic-btn:active {
  transform: scale(0.96);
}

.mic-btn:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 4px;
}

.mic-btn.recording {
  background: linear-gradient(145deg, var(--accent), #c0392b);
  box-shadow:
    0 4px 32px var(--accent-glow),
    0 0 0 1px rgba(233, 69, 96, 0.3);
  animation: mic-glow 1.4s ease-in-out infinite alternate;
}

@keyframes mic-glow {
  from { box-shadow: 0 4px 24px var(--accent-glow), 0 0 0 1px rgba(233, 69, 96, 0.3); }
  to   { box-shadow: 0 4px 48px rgba(233, 69, 96, 0.7), 0 0 0 1px rgba(233, 69, 96, 0.5); }
}

.mic-icon {
  width: 36px;
  height: 36px;
  transition: transform var(--transition);
}

.mic-btn.recording .mic-icon {
  transform: scale(1.1);
}

/* ===== Not supported ===== */
.not-supported {
  margin: 0 20px 20px;
  background: rgba(255, 80, 80, 0.1);
  border: 1px solid rgba(255, 80, 80, 0.25);
  border-radius: var(--radius);
  padding: 14px 16px;
  text-align: center;
  font-size: 0.9rem;
  color: #ff9999;
}

/* ===== Modal ===== */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.65);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  z-index: 100;
  animation: fade-in 0.2s ease;
}

.modal-overlay[hidden] {
  display: none;
}

.modal {
  background: var(--bg-2);
  border: 1px solid var(--border);
  border-radius: var(--radius) var(--radius) 0 0;
  width: 100%;
  max-width: 480px;
  padding: 0;
  animation: slide-modal 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

@media (min-height: 600px) {
  .modal-overlay {
    align-items: center;
  }
  .modal {
    border-radius: var(--radius);
    max-width: 420px;
  }
}

@keyframes slide-modal {
  from { transform: translateY(40px); opacity: 0; }
  to   { transform: translateY(0); opacity: 1; }
}

.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 20px 16px;
  border-bottom: 1px solid var(--border);
}

.modal-header h2 {
  font-size: 1.1rem;
  font-weight: 600;
}

.modal-body {
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.modal-body label {
  font-size: 0.85rem;
  color: var(--text-muted);
  font-weight: 500;
}

.modal-body input {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-size: 0.95rem;
  padding: 12px 14px;
  width: 100%;
  transition: border-color var(--transition);
  font-family: inherit;
}

.modal-body input::placeholder {
  color: var(--text-muted);
}

.modal-body input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(233, 69, 96, 0.15);
}

.field-hint {
  font-size: 0.78rem;
  color: var(--text-muted);
}

.modal-footer {
  padding: 16px 20px 24px;
  display: flex;
  justify-content: flex-end;
}

/* ===== Header actions ===== */
.header-actions {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* ===== Passive listening state (wake mode on, waiting for wake word) ===== */
.mic-ring.listening-passive::before {
  border-color: rgba(83, 52, 131, 0.5);
  animation: ring-breathe 2.8s ease-in-out infinite;
}

.mic-ring.listening-passive::after {
  border-color: rgba(83, 52, 131, 0.2);
  animation: ring-breathe 2.8s ease-in-out 1.4s infinite;
}

.mic-ring.listening-passive .mic-btn {
  animation: passive-glow 2.8s ease-in-out infinite alternate;
}

@keyframes ring-breathe {
  0%, 100% { transform: scale(1);    opacity: 0.7; }
  50%       { transform: scale(1.4); opacity: 0; }
}

@keyframes passive-glow {
  from { box-shadow: 0 4px 24px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(83, 52, 131, 0.15); }
  to   { box-shadow: 0 4px 32px rgba(83, 52, 131, 0.25), 0 0 0 3px rgba(83, 52, 131, 0.35); }
}

/* Wake word button active state */
.icon-btn.wake-active {
  color: var(--accent);
  background: rgba(233, 69, 96, 0.12);
  border-color: rgba(233, 69, 96, 0.3);
  animation: wake-btn-pulse 2.5s ease-in-out infinite;
}

@keyframes wake-btn-pulse {
  0%, 100% { box-shadow: 0 0 0 0 rgba(233, 69, 96, 0); }
  50%       { box-shadow: 0 0 0 4px rgba(233, 69, 96, 0.15); }
}

/* ===== Utilities ===== */
@keyframes fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

/* Safe area for notch phones */
@supports (padding-bottom: env(safe-area-inset-bottom)) {
  .mic-section {
    padding-bottom: calc(36px + env(safe-area-inset-bottom));
  }
}

input.content:
'use strict';

/* ===== DOM refs ===== */
const quickBtn      = document.getElementById('quick-btn');
const quickRing     = document.getElementById('quick-ring');
const brainstormBtn = document.getElementById('brainstorm-btn');
const brainstormRing = document.getElementById('brainstorm-ring');
const micHint       = document.getElementById('mic-hint');
const liveTranscript = document.getElementById('live-transcript');
const liveText      = document.getElementById('live-text');
const transcriptBar = document.getElementById('transcript-bar');
const transcriptText = document.getElementById('transcript-text');
const sendBtn       = document.getElementById('send-btn');
const discardBtn    = document.getElementById('discard-btn');
const messagesEl    = document.getElementById('messages');
const messagesEmpty = document.getElementById('messages-empty');
const notSupported  = document.getElementById('not-supported');
const settingsBtn   = document.getElementById('settings-btn');
const modalOverlay  = document.getElementById('modal-overlay');
const modalClose    = document.getElementById('modal-close');
const webhookInput  = document.getElementById('webhook-url');
const saveSettings  = document.getElementById('save-settings');
const wakeBtn       = document.getElementById('wake-btn');

/* ===== State ===== */
let recognition     = null;
let isListening     = false;
let activeMode      = null; // 'quick' | 'brainstorm' | null
let finalTranscript = '';
let interimText     = '';
let silenceTimer    = null;
const SILENCE_DELAY = 3500; // ms — only used in quick mode

/* ===== Brainstorm continuity ===== */
// Chrome stops continuous recognition periodically; we restart seamlessly in brainstorm mode
// and preserve accumulated transcript across restarts.
let brainstormAccumulator  = '';
let _brainstormRestarting  = false;

/* ===== Wake word state ===== */
let wakeRecognition       = null;
let wakeMode              = false;
let wakeTriggered         = false; // transitioning from wake → main recording
let wakeTriggeredRecording = false; // current recording was initiated by wake word
let wakeRestartTimer      = null;
const WAKE_PHRASES        = ['hey chill', 'hey chil']; // core phrase + common partial

/* ===== Audio Feedback ===== */
let audioCtx = null;

function getAudioContext() {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  }
  if (audioCtx.state === 'suspended') {
    audioCtx.resume();
  }
  return audioCtx;
}

// Prime the AudioContext on first user interaction so it's ready for hands-free sends
function primeAudio() {
  try { getAudioContext(); } catch (_) {}
}

function _playTone(ctx, frequency, startTime, duration, gain) {
  const osc  = ctx.createOscillator();
  const amp  = ctx.createGain();
  osc.connect(amp);
  amp.connect(ctx.destination);
  osc.type = 'sine';
  osc.frequency.setValueAtTime(frequency, startTime);
  amp.gain.setValueAtTime(0, startTime);
  amp.gain.linearRampToValueAtTime(gain, startTime + 0.01);
  amp.gain.exponentialRampToValueAtTime(0.001, startTime + duration);
  osc.start(startTime);
  osc.stop(startTime + duration);
}

function playSuccessSound() {
  // Prefer speech synthesis — "Got it" is immediately understood
  if ('speechSynthesis' in window) {
    const utt = new SpeechSynthesisUtterance('Got it');
    utt.rate   = 1.1;
    utt.pitch  = 1.1;
    utt.volume = 1;
    window.speechSynthesis.speak(utt);
    return;
  }
  // Fallback: ascending double chime
  try {
    const ctx = getAudioContext();
    const now = ctx.currentTime;
    _playTone(ctx, 880,  now,        0.22, 0.30); // A5
    _playTone(ctx, 1320, now + 0.18, 0.38, 0.25); // E6
  } catch (e) {
    console.warn('Audio playback failed:', e);
  }
}

function playFailureSound() {
  // Descending dissonant triple-tone — distinct "uh-oh" signal
  try {
    const ctx = getAudioContext();
    const now = ctx.currentTime;
    _playTone(ctx, 330, now,        0.18, 0.40); // E4
    _playTone(ctx, 262, now + 0.15, 0.18, 0.40); // C4
    _playTone(ctx, 196, now + 0.30, 0.45, 0.35); // G3
  } catch (e) {
    console.warn('Audio playback failed:', e);
  }
}

/* ===== Service Worker ===== */
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('sw.js').catch(() => {/* silent */});
}

/* ===== Speech Recognition setup ===== */
const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

if (!SpeechRecognition) {
  notSupported.hidden = false;
  quickBtn.disabled = true;
  quickBtn.setAttribute('aria-disabled', 'true');
  brainstormBtn.disabled = true;
  brainstormBtn.setAttribute('aria-disabled', 'true');
} else {
  initRecognition();
}

function initRecognition() {
  recognition = new SpeechRecognition();
  recognition.continuous     = true;
  recognition.interimResults = true;
  recognition.lang           = navigator.language || 'en-US';
  recognition.maxAlternatives = 1;

  recognition.onstart = () => {
    if (_brainstormRestarting) {
      // Seamless brainstorm restart — preserve accumulated transcript, don't reset UI
      isListening = true;
      finalTranscript = brainstormAccumulator;
      interimText = '';
      _brainstormRestarting = false;
      return;
    }
    isListening = true;
    finalTranscript = '';
    brainstormAccumulator = '';
    interimText = '';
    setRecordingUI(true, activeMode);
  };

  recognition.onresult = (event) => {
    let interim = '';
    for (let i = event.resultIndex; i < event.results.length; i++) {
      const result = event.results[i];
      if (result.isFinal) {
        finalTranscript += result[0].transcript + ' ';
      } else {
        interim += result[0].transcript;
      }
    }
    interimText = interim;
    const displayText = (finalTranscript + interim).trim();
    updateLiveText(displayText);

    // Silence timer only applies to quick mode
    if (activeMode === 'quick') {
      resetSilenceTimer();
    }
  };

  recognition.onerror = (event) => {
    // 'no-speech' is common and expected — just stop cleanly
    if (event.error !== 'no-speech') {
      console.warn('Speech recognition error:', event.error);
    }
    _brainstormRestarting = false;
    stopListening();
  };

  recognition.onend = () => {
    if (isListening && activeMode === 'brainstorm') {
      // Chrome stops continuous recognition periodically — restart seamlessly
      brainstormAccumulator = finalTranscript;
      _brainstormRestarting = true;
      setTimeout(() => {
        if (isListening && activeMode === 'brainstorm') {
          try {
            recognition.start();
          } catch (_) {
            _brainstormRestarting = false;
            brainstormAccumulator = '';
            isListening = false;
            finishRecording();
          }
        } else {
          _brainstormRestarting = false;
        }
      }, 150);
      return;
    }
    // onend fires when recognition stops for any reason
    if (isListening) {
      // We didn't call stop manually yet; auto-stop happened
      finishRecording();
    }
  };
}

function resetSilenceTimer() {
  clearTimeout(silenceTimer);
  silenceTimer = setTimeout(() => {
    if (isListening) stopListening();
  }, SILENCE_DELAY);
}

/* ===== Recording controls ===== */
function startListening(mode) {
  if (!recognition || isListening) return;
  activeMode = mode;
  hideTranscriptBar();

  // Ensure wake recognition is stopped before starting main recording
  if (wakeMode) stopWakeRecognition();

  try {
    recognition.start();
  } catch (e) {
    console.warn('Could not start recognition:', e);
    // Re-init in case of invalid state
    initRecognition();
    try { recognition.start(); } catch (_) {}
  }

  if (mode === 'quick') {
    resetSilenceTimer();
  }
}

function stopListening() {
  clearTimeout(silenceTimer);
  _brainstormRestarting = false; // prevent auto-restart in brainstorm
  isListening = false; // mark before calling stop so onend doesn't re-trigger finishRecording
  if (recognition) {
    try { recognition.stop(); } catch (_) {}
  }
  finishRecording();
}

function finishRecording() {
  const mode = activeMode;
  setRecordingUI(false, mode);
  const text = finalTranscript.trim();
  brainstormAccumulator = '';
  activeMode = null;
  if (text) {
    if (wakeTriggeredRecording) {
      // Hands-free path: auto-send without requiring a tap
      sendMessage(text);
    } else {
      showTranscriptBar(text);
    }
  }
  wakeTriggeredRecording = false;
  // Resume passive wake word listening if mode is active
  if (wakeMode) scheduleWakeRestart();
  updateWakeHint();
}

/* ===== UI state helpers ===== */
function setRecordingUI(recording, mode) {
  const quickActive      = recording && mode === 'quick';
  const brainstormActive = recording && mode === 'brainstorm';

  // Quick button
  quickBtn.classList.toggle('recording', quickActive);
  quickRing.classList.toggle('recording', quickActive);
  quickBtn.setAttribute('aria-pressed', quickActive ? 'true' : 'false');
  quickBtn.setAttribute('aria-label', quickActive ? 'Stop recording' : 'Quick Request – tap to speak');

  // Brainstorm button
  brainstormBtn.classList.toggle('recording', brainstormActive);
  brainstormRing.classList.toggle('recording', brainstormActive);
  brainstormBtn.setAttribute('aria-pressed', brainstormActive ? 'true' : 'false');
  brainstormBtn.setAttribute('aria-label', brainstormActive ? 'Stop brainstorm recording' : 'Brainstorm – tap for continuous recording');

  // Shared hint
  if (quickActive) {
    micHint.textContent = 'Listening… tap Quick to stop';
    micHint.classList.add('active');
    micHint.classList.remove('brainstorm-active');
  } else if (brainstormActive) {
    micHint.textContent = 'Recording… tap Brainstorm to stop';
    micHint.classList.add('active', 'brainstorm-active');
  } else {
    micHint.classList.remove('active', 'brainstorm-active');
    updateWakeHint();
  }

  liveTranscript.hidden = !recording;
  if (!recording) {
    liveText.textContent = 'Listening…';
    liveText.classList.remove('has-text');
  }
}

function updateLiveText(text) {
  if (text) {
    liveText.textContent = text;
    liveText.classList.add('has-text');
  } else {
    liveText.textContent = 'Listening…';
    liveText.classList.remove('has-text');
  }
}

function showTranscriptBar(text) {
  transcriptText.textContent = text;
  transcriptBar.hidden = false;
}

function hideTranscriptBar() {
  transcriptBar.hidden = true;
  transcriptText.textContent = '';
}

/* ===== Button click handlers ===== */
quickBtn.addEventListener('click', () => {
  primeAudio();
  if (isListening && activeMode === 'quick') {
    stopListening();
  } else if (!isListening) {
    wakeTriggeredRecording = false; // manual tap — show transcript bar after
    startListening('quick');
  }
});

brainstormBtn.addEventListener('click', () => {
  primeAudio();
  if (isListening && activeMode === 'brainstorm') {
    stopListening();
  } else if (!isListening) {
    wakeTriggeredRecording = false;
    startListening('brainstorm');
  }
});

/* ===== Send / Discard ===== */
